function check_settlement_init_cannot_be_reinitialized(address attacker, address owner, address[] memory managers, uint256 chainId, string memory chainName, uint256 requiredValidators, address signatureVerifier) public {
    // Assume contract is already initialized (owner is set)
    vm.assume(settlement.owner() != address(0));
    vm.assume(attacker != settlement.owner());

    vm.prank(attacker);
    try settlement._Settlement_init(owner, managers, chainId, chainName, requiredValidators, signatureVerifier) {
        assert(false); // Should not succeed - reinitialization by attacker
    } catch {
        // Expected: should revert
    }
}
